import { setStyles } from '../../../../utils/zcsvgutils';

/**
 *
 * @constructor
 */
export function SHOW_SELECTION_BOX(instanceMap) {
    let eventManager = this,
        brushInstance = instanceMap.instance,
        brushOptions = eventManager.chart.systemConf.chart.brush;

    setStyles(brushInstance._selection, brushOptions.selectionArea);
}

/**
 *
 * @param instanceMap
 * @constructor
 */
export function HIDE_SELECTION_BOX(instanceMap) {
    instanceMap.instance.reset();
}
